import React from 'react';

const LoadingSpinner = ({ message = "Loading...", size = "medium", fullScreen = false }) => {
  // 根据size参数确定spinner的大小
  const spinnerSize = {
    small: "h-4 w-4 border-2",
    medium: "h-8 w-8 border-b-2",
    large: "h-12 w-12 border-b-3",
  }[size] || "h-8 w-8 border-b-2";

  // 如果是全屏模式
  if (fullScreen) {
    return (
      <div className="fixed inset-0 bg-gray-50 bg-opacity-75 flex items-center justify-center z-50">
        <div className="text-center">
          <div className={`inline-block animate-spin rounded-full ${spinnerSize} border-blue-600`}></div>
          <p className="mt-2 text-gray-700 font-medium">{message}</p>
        </div>
      </div>
    );
  }

  // 默认内联模式
  return (
    <div className="flex items-center justify-center p-4">
      <div className={`inline-block animate-spin rounded-full ${spinnerSize} border-blue-600`}></div>
      <p className="ml-2 text-gray-700">{message}</p>
    </div>
  );
};

export default LoadingSpinner;
